// Rate limiting for password attempts
const MAX_ATTEMPTS = 5;
const LOCKOUT_DURATION_MS = 5 * 60 * 1000; // 5 minutes

const checkRateLimit = async () => {
  try {
    const attemptsStr = await AsyncStorage.getItem('@auth_attempts');
    const lockoutStr = await AsyncStorage.getItem('@auth_lockout');

    if (lockoutStr) {
      const lockoutTime = parseInt(lockoutStr, 10);
      if (Date.now() - lockoutTime < LOCKOUT_DURATION_MS) {
        const remainingMs = LOCKOUT_DURATION_MS - (Date.now() - lockoutTime);
        const remainingMin = Math.ceil(remainingMs / 60000);
        return {
          allowed: false,
          message: `Too many attempts. Try again in ${remainingMin} minute(s).`,
        };
      } else {
        await AsyncStorage.multiRemove(['@auth_attempts', '@auth_lockout']);
        return { allowed: true, attempts: 0 };
      }
    }

    const attempts = attemptsStr ? parseInt(attemptsStr, 10) : 0;
    return { allowed: true, attempts };
  } catch (error) {
    return { allowed: true, attempts: 0 };
  }
};

const recordFailedAttempt = async () => {
  try {
    const attemptsStr = await AsyncStorage.getItem('@auth_attempts');
    const attempts = (attemptsStr ? parseInt(attemptsStr, 10) : 0) + 1;
    await AsyncStorage.setItem('@auth_attempts', attempts.toString());

    if (attempts >= MAX_ATTEMPTS) {
      await AsyncStorage.setItem('@auth_lockout', Date.now().toString());
    }

    return attempts;
  } catch (error) {
    return 0;
  }
};

const clearFailedAttempts = async () => {
  try {
    await AsyncStorage.multiRemove(['@auth_attempts', '@auth_lockout']);
  } catch (error) {
    // Silent fail
  }
};

// Login Screen Component
const LoginScreen = ({ onAuthenticated }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);
  const [errorMessage, setErrorMessage] = useState('');
  const [isLocked, setIsLocked] = useState(false);

  useEffect(() => {
    initBiometrics();
    checkLockStatus();
  }, []);

  const checkLockStatus = async () => {
    const { allowed, message } = await checkRateLimit();
    if (!allowed) {
      setIsLocked(true);
      setErrorMessage(message);
    }
  };

  const initBiometrics = async () => {
    const { available, biometryType: type } = await checkBiometricAvailability();
    setBiometricAvailable(available);
    setBiometryType(type);

    if (available) {
      await createBiometricKeys();
      // Auto-prompt biometric on mount
      handleBiometricAuth();
    }
  };

  const handleBiometricAuth = useCallback(async () => {
    if (!biometricAvailable && !biometryType) {
      // Re-check in case state hasn't updated yet
      const { available, biometryType: type } = await checkBiometricAvailability();
      if (!available) return;
      setBiometricAvailable(available);
      setBiometryType(type);
    }

    setLoading(true);
    setErrorMessage('');

    try {
      // Try signature-based auth first (more secure)
      let result = await authenticateWithSignature();

      if (!result.success) {
        // Fallback to simple prompt
        result = await authenticateWithBiometrics(biometryType);
      }

      if (result.success) {
        await setAuthenticatedFlag();
        await clearFailedAttempts();
        onAuthenticated();
      } else if (result.error && result.error !== 'Authentication cancelled') {
        setErrorMessage('Biometric authentication failed. Please use password.');
      }
    } catch (error) {
      setErrorMessage('Biometric authentication error. Please use password.');
    } finally {
      setLoading(false);
    }
  }, [biometricAvailable, biometryType, onAuthenticated]);

  const handlePasswordLogin = async () => {
    const { allowed, message } = await checkRateLimit();
    if (!allowed) {
      setIsLocked(true);
      setErrorMessage(message);
      return;
    }

    setLoading(true);
    setErrorMessage('');

    try {
      const trimmedUsername = username.trim();
      const result = await validatePassword(trimmedUsername, password);

      if (result.success) {
        await setAuthenticatedFlag();
        await clearFailedAttempts();
        setPassword(''); // Clear sensitive data
        onAuthenticated();
      } else {
        const attempts = await recordFailedAttempt();
        const remaining = MAX_ATTEMPTS - attempts;

        if (remaining <= 0) {
          setIsLocked(true);
          setErrorMessage('Too many failed attempts. Account locked for 5 minutes.');
        } else {
          setErrorMessage(
            `${result.error || 'Invalid credentials'}. ${remaining} attempt(s) remaining.`
          );
        }
      }
    } catch (error) {
      setErrorMessage('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getBiometricButtonText = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return '🔐 Sign in with Face ID';
      case BiometryTypes.TouchID:
        return '👆 Sign in with Touch ID';
      case BiometryTypes.Biometrics:
        return '👆 Sign in with Fingerprint';
      default:
        return '🔐 Sign in with Biometrics';
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Welcome Back</Text>
        <Text style={styles.subtitle}>Sign in to continue</Text>
      </View>

      {errorMessage ? (
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>{errorMessage}</Text>
        </View>
      ) : null}

      {biometricAvailable && !isLocked && (
        <TouchableOpacity
          style={[styles.biometricButton, loading && styles.disabledButton]}
          onPress={handleBiometricAuth}
          disabled={loading}
          accessibilityLabel={getBiometricButtonText()}
          accessibilityRole="button"
        >
          <Text style={styles.biometricButtonText}>{getBiometricButtonText()}</Text>
        </TouchableOpacity>
      )}

      {biometricAvailable && <View style={styles.dividerContainer}>
        <View style={styles.divider} />
        <Text style={styles.dividerText}>or use password</Text>
        <View style={styles.divider} />
      </View>}

      <View style={styles.form}>
        <TextInput
          style={styles.input}
          placeholder="Username"
          placeholderTextColor="#999"
          value={username}
          onChangeText={setUsername}
          autoCapitalize="none"
          autoCorrect={false}
          textContentType="username"
          autoComplete="username"
          editable={!loading && !isLocked}
          maxLength={256}
          accessibilityLabel="Username input"
        />
        <TextInput
          style={styles.input}
          placeholder="Password"
          placeholderTextColor="#999"
          value={password}
          onChangeText={setPassword}
          secureTextEntry
          textContentType="password"
          autoComplete="password"
          editable={!loading && !isLocked}
          maxLength={256}
          accessibilityLabel="Password input"
        />
        <TouchableOpacity
          style={[
            styles.loginButton,
            (loading || isLocked || !username.trim() || !password) && styles.disabledButton,
          ]}
          onPress={handlePasswordLogin}
          disabled={loading || isLocked || !username.trim() || !password}
          accessibilityLabel="Sign in with password"
          accessibilityRole="button"
        >
          {loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In</Text>
          )}
        </TouchableOpacity>
      </View>
    </View>
  );
};

