// Main App Component with Auth Flow
const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkExistingAuth();
  }, []);

  const checkExistingAuth = async () => {
    try {
      const authenticated = await getAuthenticatedFlag();

      if (authenticated) {
        // Re-verify with biometrics before granting access
        const { available } = await checkBiometricAvailability();

        if (available) {
          const result = await authenticateWithBiometrics();
          if (result.success) {
            // Refresh the timestamp
            await setAuthenticatedFlag();
            setIsAuthenticated(true);
          } else {
            // Biometric re-auth failed, require full login
            await clearAuthenticatedFlag();
            setIsAuthenticated(false);
          }
        } else {
          // No biometrics available, trust the stored flag (within expiry)
          setIsAuthenticated(true);
        }
      } else {
        setIsAuthenticated(false);
      }
    } catch (error) {
      console.error('Auth check failed:', error);
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuthenticated = useCallback(() => {
    setIsAuthenticated(true);
  }, []);

  const handleLogout = useCallback(async () => {
    try {
      await clearAuthenticatedFlag();
      await clearFailedAttempts();
      // In production, also invalidate server-side session/tokens
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      setIsAuthenticated(false);
    }
  }, []);

  if (isLoading) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Verifying authentication...</Text>
      </View>
    );
  }

  if (isAuthenticated) {
    return <HomeScreen onLogout={handleLogout} />;
  }

  return <LoginScreen onAuthenticated={handleAuthenticated} />;
};

